export type ParamSchema<T extends string = DefaultSchemaKeys> = BaseParamSchema &
  ValidatorsSchema &
  SanitizersSchema & {
    [K in T]?: K extends keyof BaseParamSchema
      ? BaseParamSchema[K]
      : K extends keyof ValidatorsSchema
      ? ValidatorsSchema[K]
      : K extends keyof SanitizersSchema
      ? SanitizersSchema[K]
      : CustomValidatorSchemaOptions | CustomSanitizerSchemaOptions;
  };

switch (encoding) {
  case 'deflate':
    debug('inflate body')
    return zlib.createInflate()
  case 'gzip':
    debug('gunzip body')
    return zlib.createGunzip()
  case 'br':
    debug('brotli decompress body')
    return zlib.createBrotliDecompress()
  default:
    throw createError(415, 'unsupported content encoding "' + encoding + '"', {
      encoding: encoding,
      type: 'encoding.unsupported'
    })
}

res.json = function json(obj) {
  // settings
  var app = this.app;
  var escape = app.get('json escape')
  var replacer = app.get('json replacer');
  var spaces = app.get('json spaces');
  var body = stringify(obj, replacer, spaces, escape)

  // content-type
  if (!this.get('Content-Type')) {
    this.set('Content-Type', 'application/json');
  }

  return this.send(body);
};

serveIndex.json = function _json (req, res, files, next, dir, showUp, icons, path) {
  // stat all files
  stat(path, files, function (err, fileList) {
    if (err) return next(err)

    // sort file list
    fileList.sort(fileSort)

    // serialize
    var body = JSON.stringify(fileList.map(function (file) {
      return file.name
    }))

    send(res, 'application/json', body)
  })
};

serveIndex.plain = function _plain (req, res, files, next, dir, showUp, icons, path) {
  // stat all files
  stat(path, files, function (err, fileList) {
    if (err) return next(err)

    // sort file list
    fileList.sort(fileSort)

    // serialize
    var body = fileList.map(function (file) {
      return file.name
    }).join('\n') + '\n'

    send(res, 'text/plain', body)
  })
};

export class JsonResult implements IHttpActionResult {
  constructor(
    public readonly json: unknown,
    public readonly statusCode: number,
  ) {}

  public async executeAsync(): Promise<HttpResponseMessage> {
    const response: HttpResponseMessage = new HttpResponseMessage(
      this.statusCode,
    );
    response.content = new JsonContent(this.json);

    return response;
  }
}

