export type InlinedTediousOptions = Omit<
  NonUndefined<Tedious.ConnectionConfiguration['options']>,
  // Default nullability of columns is not needed as Sequelize explicitly sets it,
  // and this option will be confusing with Sequelize's option about default nullability.
  | 'enableAnsiNullDefault'
  | 'camelCaseColumns'
  | 'columnNameReplacer'
  | 'enableQuotedIdentifier'
  | 'useUTC'
  | 'useColumnNames'
  // Conflicts with our own isolationLevel option, which does the same thing
  | 'isolationLevel'
>;

Reflect.ownKeys(source).forEach((key) => {
  // respects property descriptors and the prototype chain more explicitly, which is important for objects with getter/setter.
  const descriptor = Object.getOwnPropertyDescriptor(source, key);

  if (descriptor) {
    if (!isFunction(descriptor.value)) {
      Object.defineProperty(clone, key, {
        ...descriptor,
        value: deepClone(descriptor.value, stack)
      });
    } else {
      Object.defineProperty(clone, key, descriptor);
    }
  }
});

return (...args: DecoratorParameters) => {
  const [target, propertyKey] = args;
  const type = decoratorTypeOf(args);
  switch (type) {
    case DecoratorTypes.CLASS:
      decorateMethodsOf(target, Intercept(interceptor, options));
      break;
    case DecoratorTypes.METHOD:
      return bindIntercept(target, propertyKey, interceptor, options);
  }
};

export class AuthorizationCheckerNotDefinedError extends InternalServerError {
  name = 'AuthorizationCheckerNotDefinedError';

  constructor() {
    super(
      `Cannot use @Authorized decorator. Please define authorizationChecker function in routing-controllers action before using it.`
    );
    Object.setPrototypeOf(this, AuthorizationCheckerNotDefinedError.prototype);
  }
}

